// Simulates a running A/B test over 14 days of real traffic.
// Control (A) has a true 5% conversion rate. Variant (B) is deliberately WORSE
// (3.5%) so the Kill-Switch has a real losing variant to catch -- exactly the
// situation this project is designed to detect and stop early.

const days = 14;
const visitorsPerDayA = 500;
const visitorsPerDayB = 500;
const trueRateA = 0.05;
const trueRateB = 0.035;

function simulateConversions(visitors, rate) {
  let conversions = 0;
  for (let i = 0; i < visitors; i++) {
    if (Math.random() < rate) conversions++;
  }
  return conversions;
}

const rows = [];
let cumVisitorsA = 0, cumConversionsA = 0;
let cumVisitorsB = 0, cumConversionsB = 0;

for (let day = 1; day <= days; day++) {
  const convA = simulateConversions(visitorsPerDayA, trueRateA);
  const convB = simulateConversions(visitorsPerDayB, trueRateB);

  cumVisitorsA += visitorsPerDayA;
  cumConversionsA += convA;
  cumVisitorsB += visitorsPerDayB;
  cumConversionsB += convB;

  rows.push({
    json: {
      day,
      visitors_a: cumVisitorsA,
      conversions_a: cumConversionsA,
      visitors_b: cumVisitorsB,
      conversions_b: cumConversionsB
    }
  });
}

return rows;

// ---- LEARNING NOTE ----
// This node is the core logic. It does 3 things:
// 1. Calculates conversion rates for both variants using the LATEST cumulative day
// 2. Checks statistical significance using a stricter, day-adjusted boundary --
//    because checking a test's results every single day using a fixed 95%
//    threshold (z > 1.96) inflates false positives. This is a real, well-known
//    mistake called "the peeking problem." The fix here is a simplified version
//    of what's called a Pocock-style sequential boundary: the more days you've
//    already checked, the stricter the bar needs to be to call it significant.
// 3. Translates the losing variant into an estimated dollar cost.

const days = $input.all().map(i => i.json);
const latest = days[days.length - 1];

const pA = latest.conversions_a / latest.visitors_a;
const pB = latest.conversions_b / latest.visitors_b;

const pPooled = (latest.conversions_a + latest.conversions_b) / (latest.visitors_a + latest.visitors_b);
const se = Math.sqrt(pPooled * (1 - pPooled) * (1 / latest.visitors_a + 1 / latest.visitors_b));
const z = se === 0 ? 0 : (pB - pA) / se;

const daysSoFar = latest.day;
// Simplified Pocock-style boundary: tightens slightly the more days you've peeked at
const adjustedThreshold = 1.96 + Math.log(daysSoFar) * 0.15;

const isSignificant = Math.abs(z) > adjustedThreshold;
const bIsWorse = pB < pA;

// Business impact: assumed average order value, configurable
const avgOrderValue = 45;
const lostConversions = Math.max(0, (pA - pB)) * latest.visitors_b;
const dollarImpact = lostConversions * avgOrderValue;

let severity = 'low';
if (isSignificant && bIsWorse && dollarImpact > 300) severity = 'high';
else if (bIsWorse && dollarImpact > 100) severity = 'medium';

return [{
  json: {
    day: latest.day,
    conversion_rate_a_pct: Number((pA * 100).toFixed(2)),
    conversion_rate_b_pct: Number((pB * 100).toFixed(2)),
    z_score: Number(z.toFixed(2)),
    significance_threshold_used: Number(adjustedThreshold.toFixed(2)),
    is_statistically_significant: isSignificant,
    dollar_impact_usd: Number(dollarImpact.toFixed(2)),
    severity
  }
}];
